n8n_update_partial_workflow({id: "def", operations: [{type: "addConnection", source: "IF", target: "Error Handler", branch: "false"}]})
```

```javascript
// Smart parameter: Switch node case routing
n8n_update_partial_workflow({id: "ghi", operations: [
  {type: "addConnection", source: "Switch", target: "Handler A", case: 0},
  {type: "addConnection", source: "Switch", target: "Handler B", case: 1},
  {type: "addConnection", source: "Switch", target: "Handler C", case: 2}
]})
```

```javascript
// Rewire with smart parameter
n8n_update_partial_workflow({id: "jkl", operations: [{type: "rewireConnection", source: "IF", from: "Old True Handler", to: "New True Handler", branch: "true"}]})
```

```javascript
// Add multiple nodes in batch
n8n_update_partial_workflow({id: "mno", operations: [
  {type: "addNode", node: {name: "Filter", type: "n8n-nodes-base.filter", position: [400, 300], parameters: {}}},
  {type: "addNode", node: {name: "Transform", type: "n8n-nodes-base.set", position: [600, 300], parameters: {}}},
  {type: "addConnection", source: "Filter", target: "Transform"}
]})
```

```javascript
// Clean up stale connections after node renames/deletions
n8n_update_partial_workflow({id: "pqr", operations: [{type: "cleanStaleConnections"}]})
```

```javascript
// Remove connection gracefully (no error if it doesn't exist)
n8n_update_partial_workflow({id: "stu", operations: [{type: "removeConnection", source: "Old Node", target: "Target", ignoreErrors: true}]})
```

```javascript
// Best-effort mode: apply what works, report what fails
n8n_update_partial_workflow({id: "vwx", operations: [
  {type: "updateName", name: "Fixed Workflow"},
  {type: "removeConnection", source: "Broken", target: "Node"},
  {type: "cleanStaleConnections"}
], continueOnError: true})
```

```javascript
// Update node parameter
n8n_update_partial_workflow({id: "yza", operations: [{type: "updateNode", nodeName: "HTTP Request", updates: {"parameters.url": "https://api.example.com"}}]})
```

```javascript
// Validate before applying
n8n_update_partial_workflow({id: "bcd", operations: [{type: "removeNode", nodeName: "Old Process"}], validateOnly: true})
```

```javascript

// ============ AI CONNECTION EXAMPLES ============
```

```javascript
// Connect language model to AI Agent
n8n_update_partial_workflow({id: "ai1", operations: [{type: "addConnection", source: "OpenAI Chat Model", target: "AI Agent", sourceOutput: "ai_languageModel"}]})
```

```javascript
// Connect tool to AI Agent
n8n_update_partial_workflow({id: "ai2", operations: [{type: "addConnection", source: "HTTP Request Tool", target: "AI Agent", sourceOutput: "ai_tool"}]})
