      {
        "parameters": {
          "jsCode": "return [{\n  json: {\n    user_id: 'boss',\n    thread_id: 'k3rn:default',\n    message: $input.first().json.chatInput,\n    timestamp: new Date().toISOString()\n  }\n}];"
        },
        "id": "k3rn-v0-session",
        "name": "SESSION_RESOLVER",
        "type": "n8n-nodes-base.code",
        "typeVersion": 2,
        "position": [
          560,
          304
        ]
      },
      {
        "parameters": {
          "operation": "executeQuery",
          "query": "=SELECT role, content, metadata, created_at\nFROM sep_messages\nWHERE thread_id = '{{ $json.thread_id }}'\n  AND user_id = '{{ $json.user_id }}'\nORDER BY created_at DESC\nLIMIT 12;",
          "options": {}
        },
        "id": "k3rn-v0-sep-retrieve",
        "name": "SEP_RETRIEVE",
        "type": "n8n-nodes-base.postgres",
        "typeVersion": 2.6,
        "position": [
          864,
          304
        ],
        "credentials": {
          "postgres": {
            "id": "Nl0ptIY5ANjEApX8",
            "name": "Postgres 1"
          }
        },
        "alwaysOutputData": true,
        "retryOnFail": true
      },
      {
        "parameters": {
          "jsCode": "const allItems = $input.all();\n\nconst sepContext = allItems\n  .filter(item => item.json.role)\n  .map(item => {\n    const role = item.json.role || 'unknown';\n    const content = item.json.content || '';\n    const ts = item.json.created_at\n      ? new Date(item.json.created_at).toISOString()\n      : '';\n    return `[${role.toUpperCase()}] ${ts}\\n${content}`;\n  })\n  .join('\\n\\n---\\n\\n');\n\nconst session = $('SESSION_RESOLVER').first().json;\n\nreturn [{\n  json: {\n    user_id: session.user_id,\n    thread_id: session.thread_id,\n    message: session.message,\n    timestamp: session.timestamp,\n    sep_context: sepContext,\n    sep_item_count: allItems.filter(item => item.json.role).length\n  },\n  pairedItem: { item: 0 }\n}];"
        },
        "id": "k3rn-v0-sep-aggregator",
        "name": "SEP_AGGREGATOR",
        "type": "n8n-nodes-base.code",
        "typeVersion": 2,
        "position": [
          1032,
          304
        ]
      },
      {
        "parameters": {
          "promptType": "define",
          "text": "={{ $json.message }}",
          "options": {
            "systemMessage": "Tu es le cerveau classificateur de K3rn.labs.\nTon unique role : analyser le message utilisateur et produire\nun JSON de routage. Rien d'autre. Aucune reponse conversationnelle.\n\nRegles de routage :\n- Si le message contient une idee, concept, projet, ou venture a developper\n  → route = \"ideation\"\n- Si le message pose une question generale, demande une clarification,\n  ou dit \"ok\", \"d'accord\", \"continue\", ou autre reponse courte\n  → route = \"default\"\n\nReponds UNIQUEMENT avec ce JSON, sans aucun texte avant ou apres :\n{\n  \"route\": \"ideation\" | \"default\",\n  \"reason\": \"une phrase expliquant le choix\",\n  \"language\": \"fr\" | \"en\"\n}",
            "maxIterations": 3
          }
        },
        "id": "k3rn-v0-cerveau",
        "name": "CERVEAU++",
        "type": "@n8n/n8n-nodes-langchain.agent",
        "typeVersion": 3.1,
        "position": [
          1300,
          304
        ]
      },
      {
        "parameters": {
          "model": {
            "__rl": true,
            "mode": "id",
            "value": "gpt-4o-mini"
          },
          "responsesApiEnabled": false,
          "options": {
            "timeout": 120000
          }
        },
        "id": "k3rn-v0-llm-cerveau",
        "name": "LLM Cerveau",
        "type": "@n8n/n8n-nodes-langchain.lmChatOpenAi",
        "typeVersion": 1.3,
        "position": [
          1300,
          520
        ],
        "credentials": {
          "openAiApi": {
            "id": "0zCm2AMTb5pDX8Sa",
            "name": "OpenAi account"
          }
        }
      },
      {
        "parameters": {
          "jsCode": "try {\n  const raw = $json.output;\n  const cerveau = JSON.parse(raw);\n  const session = $('SEP_AGGREGATOR').first().json;\n\n  return [{\n    json: {\n      route: cerveau.route || 'default',\n      reason: cerveau.reason || '',\n      language: cerveau.language || 'fr',\n      user_id: session.user_id,\n      thread_id: session.thread_id,\n      message: session.message,\n      timestamp: session.timestamp,\n      sep_context: session.sep_context,\n      sep_item_count: session.sep_item_count\n    },\n    pairedItem: { item: 0 }\n  }];\n} catch (e) {\n  const session = $('SEP_AGGREGATOR').first().json;\n  return [{\n    json: {\n      route: 'default',\n      reason: 'JSON parse error: ' + e.message,\n      language: 'fr',\n      user_id: session.user_id,\n      thread_id: session.thread_id,\n      message: session.message,\n      timestamp: session.timestamp,\n      sep_context: session.sep_context,\n      sep_item_count: session.sep_item_count\n    },\n    pairedItem: { item: 0 }\n  }];\n}"
        },
        "id": "k3rn-v0-parse-route",
        "name": "PARSE_ROUTE",
        "type": "n8n-nodes-base.code",
        "typeVersion": 2,
        "position": [
          1568,
