                "conditions": {
                  "conditions": [
                    {
                      "leftValue": "={{ $json.route }}",
                      "rightValue": "ideation",
                      "operator": {
                        "type": "string",
                        "operation": "equals"
                      }
                    }
                  ]
                },
                "renameOutput": true,
                "outputKey": "ideation"
              }
            ]
          },
          "options": {
            "fallbackOutput": "extra",
            "allMatchingOutputs": false
          }
        },
        "id": "k3rn-v0-router",
        "name": "ROUTER",
        "type": "n8n-nodes-base.switch",
        "typeVersion": 3.4,
        "position": [
          1836,
