        ]
      },
      {
        "parameters": {
          "promptType": "define",
          "text": "=user_id={{ $json.user_id }}\nthread_id={{ $json.thread_id }}\nmessage={{ $json.message }}\n\nSEP_CONTEXT (last messages):\n{{ $json.sep_context }}\n\nRemember: act immediately.\nSTEP 1: Process the user message using the SEP context above.\nSTEP 2: Produce a single, clear response.\nSTEP 3: The system will persist this exchange automatically.",
          "options": {
