// Perplexity Search — toolCode v1.3
try {
  // toolCode injects 'query' from LangChain; fallback to $input
  const q = (typeof query !== 'undefined' && query)
    ? query
    : ($input.first().json.query || $input.first().json.input || $input.first().json.chatInput || 'no query');

  const response = await fetch('https://api.perplexity.ai/chat/completions', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer 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',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: 'sonar-pro',
      messages: [{ role: 'user', content: q }],
      return_citations: true,
      search_recency_filter: 'month'
    })
  });

  if (!response.ok) {
    const errText = await response.text();
    return 'ERROR: Perplexity HTTP ' + response.status + ' — ' + errText;
  }

  const data = await response.json();
  const content = data.choices?.[0]?.message?.content || 'No results';
  const citations = (data.citations || []).join('\n');
  return content + '\n\nSources:\n' + citations;
} catch (err) {
  return 'ERROR: Perplexity fetch failed — ' + err.message;
}

