return [{
  json: {
    user_id: 'boss',
    thread_id: 'k3rn:default',
    message: $input.first().json.chatInput,
    timestamp: new Date().toISOString()
  }
}];

const allItems = $input.all();
const sepContext = allItems
  .filter(item => item.json.role)
  .map(item => {
    const role = item.json.role || 'unknown';
    const content = item.json.content || '';
    const ts = item.json.created_at ? new Date(item.json.created_at).toISOString() : '';
    return `[${role.toUpperCase()}] ${ts}\n${content}`;
  })
  .join('\n\n---\n\n');
const session = $('SESSION_RESOLVER').first().json;
return [{
  json: {
    user_id: session.user_id,
    thread_id: session.thread_id,
    message: session.message,
    timestamp: session.timestamp,
    sep_context: sepContext,
    sep_item_count: allItems.filter(item => item.json.role).length
  },
  pairedItem: { item: 0 }
}];

try {
  const raw = $json.output;
  const cerveau = JSON.parse(raw);
  const session = $('SEP_AGGREGATOR').first().json;
  return [{ json: { route: cerveau.route || 'default', reason: cerveau.reason || '', language: cerveau.language || 'fr', user_id: session.user_id, thread_id: session.thread_id, message: session.message, timestamp: session.timestamp, sep_context: session.sep_context, sep_item_count: session.sep_item_count }, pairedItem: { item: 0 } }];
} catch (e) {
  const session = $('SEP_AGGREGATOR').first().json;
  return [{ json: { route: 'default', reason: 'JSON parse error: ' + e.message, language: 'fr', user_id: session.user_id, thread_id: session.thread_id, message: session.message, timestamp: session.timestamp, sep_context: session.sep_context, sep_item_count: session.sep_item_count }, pairedItem: { item: 0 } }];
}

