}
return [{ json: { user_id: route.user_id, thread_id: route.thread_id, message: route.message, timestamp: route.timestamp, sep_context: route.sep_context, sep_item_count: route.sep_item_count, search_perplexity: perplexityResult, search_tavily: tavilyResult } }];

